"use strict";exports.id=7734,exports.ids=[7734],exports.modules={17734:(e,t,a)=>{a.r(t),a.d(t,{pythonInterviews:()=>n});let n=[{question:"What is the difference between list and tuple?",answer:"Lists are mutable (their items can be modified, appended, or deleted) and defined with brackets []. Tuples are immutable (cannot be modified after creation) and defined with parentheses (). Tuples are slightly faster and can be used as keys in dictionaries.",level:"Beginner"},{question:"How is memory managed in Python?",answer:"Python manages memory using a private heap space that holds all Python objects and structures. The interpreter garbage collector uses reference counting to track object references. When an object reference count drops to zero, its memory is deallocated. It also features a cyclic garbage collector to resolve reference cycles.",level:"Intermediate"},{question:"What are Python decorators and how do you write one?",answer:"A decorator is a function that takes another function as an argument, extends or alters its behavior without modifying the actual function definition, and returns a new function. They are applied using the @decorator syntax.",level:"Advanced"}]}};